import { ref, nextTick, computed, onMounted } from 'vue';
import { ElMessage } from 'element-plus';
import api from '../utils/api';
export default {
  name: 'AIChat',
  setup() {
    const sessions = ref({});
    const currentSessionId = ref(null);
    const tempSession = ref(false);
    const currentMessages = ref([]);
    const inputMessage = ref('');
    const loading = ref(false);
    const messagesRef = ref(null);
    const messageInput = ref(null);
    const selectedModel = ref('1');
    const isStreaming = ref(true);
    const uploading = ref(false);
    const fileInput = ref(null);
    const isComposing = ref(false);

    // 侧边栏收缩/拖拽相关
    const sidebarCollapsed = ref(false);
    const sidebarWidth = ref(260);
    let isResizing = false;
    let resizeStartX = 0;
    let resizeStartWidth = 0;
    const toggleSidebar = () => {
      sidebarCollapsed.value = !sidebarCollapsed.value;
    };
    const startResize = e => {
      if (sidebarCollapsed.value) return;
      isResizing = true;
      resizeStartX = e.clientX;
      resizeStartWidth = sidebarWidth.value;
      document.body.style.cursor = 'col-resize';
      document.body.style.userSelect = 'none';
      const onMouseMove = e => {
        if (!isResizing) return;
        const delta = e.clientX - resizeStartX;
        const newWidth = Math.min(400, Math.max(180, resizeStartWidth + delta));
        sidebarWidth.value = newWidth;
      };
      const onMouseUp = () => {
        isResizing = false;
        document.body.style.cursor = '';
        document.body.style.userSelect = '';
        document.removeEventListener('mousemove', onMouseMove);
        document.removeEventListener('mouseup', onMouseUp);
      };
      document.addEventListener('mousemove', onMouseMove);
      document.addEventListener('mouseup', onMouseUp);
    };
    const renderMarkdown = text => {
      if (!text && text !== '') return '';
      return String(text).replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>').replace(/\*(.*?)\*/g, '<em>$1</em>').replace(/`(.*?)`/g, '<code>$1</code>').replace(/\n/g, '<br>');
    };
    const playTTS = async text => {
      try {
        const createResponse = await api.post('/ai/chat/tts', {
          text
        });
        if (createResponse.data && createResponse.data.status_code === 1000 && createResponse.data.task_id) {
          const taskId = createResponse.data.task_id;
          await new Promise(resolve => setTimeout(resolve, 5000));
          const maxAttempts = 30;
          const pollInterval = 2000;
          let attempts = 0;
          const pollResult = async () => {
            const queryResponse = await api.get('/ai/chat/tts/query', {
              params: {
                task_id: taskId
              }
            });
            if (queryResponse.data && queryResponse.data.status_code === 1000) {
              const taskStatus = queryResponse.data.task_status;
              if (taskStatus === 'Success' && queryResponse.data.task_result) {
                const audio = new Audio(queryResponse.data.task_result);
                audio.play();
                return true;
              } else if (taskStatus === 'Running' || taskStatus === 'Created') {
                attempts++;
                if (attempts < maxAttempts) {
                  await new Promise(resolve => setTimeout(resolve, pollInterval));
                  return await pollResult();
                } else {
                  ElMessage.error('语音合成超时');
                  return true;
                }
              } else {
                ElMessage.error('语音合成失败');
                return true;
              }
            }
            attempts++;
            if (attempts < maxAttempts) {
              await new Promise(resolve => setTimeout(resolve, pollInterval));
              return await pollResult();
            } else {
              ElMessage.error('语音合成超时');
              return true;
            }
          };
          await pollResult();
        } else {
          ElMessage.error('无法创建语音合成任务');
        }
      } catch (error) {
        console.error('TTS error:', error);
        ElMessage.error('请求语音接口失败');
      }
    };
    const loadSessions = async () => {
      try {
        const response = await api.get('/ai/chat/sessions');
        if (response.data && response.data.status_code === 1000 && Array.isArray(response.data.sessions)) {
          const sessionMap = {};
          response.data.sessions.forEach(s => {
            const sid = String(s.sessionID);
            sessionMap[sid] = {
              id: sid,
              name: s.title || `会话 ${sid}`,
              messages: []
            };
          });
          sessions.value = sessionMap;
        }
      } catch (error) {
        console.error('Load sessions error:', error);
      }
    };
    const createNewSession = () => {
      currentSessionId.value = 'temp';
      tempSession.value = true;
      currentMessages.value = [];
      nextTick(() => {
        if (messageInput.value) messageInput.value.focus();
      });
    };
    const switchSession = async sessionId => {
      if (!sessionId) return;
      currentSessionId.value = String(sessionId);
      tempSession.value = false;
      if (!sessions.value[sessionId].messages || sessions.value[sessionId].messages.length === 0) {
        try {
          const response = await api.post('/ai/chat/history', {
            sessionId: currentSessionId.value
          });
          if (response.data && response.data.status_code === 1000 && Array.isArray(response.data.history)) {
            const messages = response.data.history.map(item => ({
              role: item.is_user ? 'user' : 'assistant',
              content: item.content
            }));
            sessions.value[sessionId].messages = messages;
          }
        } catch (err) {
          console.error('Load history error:', err);
        }
      }
      currentMessages.value = [...(sessions.value[sessionId].messages || [])];
      await nextTick();
      scrollToBottom();
    };
    const deleteSession = async sessionId => {
      try {
        const response = await api.delete('/ai/chat/delete-session', {
          data: {
            sessionID: sessionId
          }
        });
        if (response.data && response.data.status_code === 1000) {
          // 从本地会话列表中移除
          const updated = {
            ...sessions.value
          };
          delete updated[sessionId];
          sessions.value = updated;
          // 如果删除的是当前会话，清空聊天区
          if (currentSessionId.value === String(sessionId)) {
            currentSessionId.value = null;
            currentMessages.value = [];
          }
          ElMessage.success('会话已删除');
        } else {
          ElMessage.error('删除失败');
        }
      } catch (err) {
        console.error('Delete session error:', err);
        ElMessage.error('删除失败，请重试');
      }
    };
    const syncHistory = async () => {
      if (!currentSessionId.value || tempSession.value) {
        ElMessage.warning('请选择已有会话进行同步');
        return;
      }
      try {
        const response = await api.post('/ai/chat/history', {
          sessionId: currentSessionId.value
        });
        if (response.data && response.data.status_code === 1000 && Array.isArray(response.data.history)) {
          const messages = response.data.history.map(item => ({
            role: item.is_user ? 'user' : 'assistant',
            content: item.content
          }));
          sessions.value[currentSessionId.value].messages = messages;
          currentMessages.value = [...messages];
          await nextTick();
          scrollToBottom();
        } else {
          ElMessage.error('无法获取历史数据');
        }
      } catch (err) {
        console.error('Sync history error:', err);
        ElMessage.error('请求历史数据失败');
      }
    };
    const sendMessage = async () => {
      if (!inputMessage.value || !inputMessage.value.trim()) {
        ElMessage.warning('请输入消息内容');
        return;
      }
      const userMessage = {
        role: 'user',
        content: inputMessage.value
      };
      const currentInput = inputMessage.value;
      inputMessage.value = '';
      currentMessages.value.push(userMessage);
      await nextTick();
      scrollToBottom();
      // 如果是临时会话，立即在侧边栏显示会话标签
      if (tempSession.value && (String(currentSessionId.value) === 'temp' || !currentSessionId.value)) {
        const tempId = 'temp_' + Date.now();
        const newSessions = {
          ...sessions.value
        };
        newSessions[tempId] = {
          id: tempId,
          name: '新会话',
          messages: [...currentMessages.value]
        };
        currentSessionId.value = tempId;
      }
      try {
        loading.value = true;
        if (isStreaming.value) {
          await handleStreaming(currentInput);
        } else {
          await handleNormal(currentInput);
        }
      } catch (err) {
        console.error('Send message error:', err);
        ElMessage.error('发送失败，请重试');
        // 移除临时会话标签
        if (currentSessionId.value && String(currentSessionId.value).startsWith('temp_')) {
          const updated = {
            ...sessions.value
          };
          delete updated[currentSessionId.value];
          sessions.value = updated;
          currentSessionId.value = null;
          tempSession.value = true;
        }
      } finally {
        if (!isStreaming.value) {
          loading.value = false;
        }
        await nextTick();
        scrollToBottom();
      }
    };
    async function handleStreaming(question) {
      const aiMessage = {
        role: 'assistant',
        content: '',
        meta: {
          status: 'streaming'
        }
      };
      const aiMessageIndex = currentMessages.value.length;
      currentMessages.value.push(aiMessage);
      if (!tempSession.value && currentSessionId.value && sessions.value[currentSessionId.value]) {
        if (!sessions.value[currentSessionId.value].messages) sessions.value[currentSessionId.value].messages = [];
        sessions.value[currentSessionId.value].messages.push({
          role: 'assistant',
          content: ''
        });
      }
      const url = tempSession.value ? '/api/ai/chat/send-stream-new-session' : '/api/ai/chat/send-stream';
      const headers = {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${localStorage.getItem('token') || ''}`
      };
      const body = tempSession.value ? {
        question: question,
        modelType: selectedModel.value
      } : {
        question: question,
        modelType: selectedModel.value,
        sessionId: currentSessionId.value
      };
      try {
        const response = await fetch(url, {
          method: 'POST',
          headers,
          body: JSON.stringify(body)
        });
        if (!response.ok) {
          loading.value = false;
          throw new Error('Network response was not ok');
        }
        const reader = response.body.getReader();
        const decoder = new TextDecoder();
        let buffer = '';
        // eslint-disable-next-line no-constant-condition
        while (true) {
          const {
            done,
            value
          } = await reader.read();
          if (done) break;
          const chunk = decoder.decode(value, {
            stream: true
          });
          buffer += chunk;
          const lines = buffer.split('\n');
          buffer = lines.pop() || '';
          for (const line of lines) {
            const trimmedLine = line.trim();
            if (!trimmedLine) continue;
            if (trimmedLine.startsWith('data:')) {
              const data = trimmedLine.slice(5).trim();
              if (data === '[DONE]') {
                loading.value = false;
                currentMessages.value[aiMessageIndex].meta = {
                  status: 'done'
                };
                currentMessages.value = [...currentMessages.value];
              } else if (data.startsWith('{')) {
                try {
                  const parsed = JSON.parse(data);
                  if (parsed.sessionId) {
                    const newSid = String(parsed.sessionId);
                    const oldSid = currentSessionId.value;
                    // 删除旧的临时会话标签
                    if (oldSid && String(oldSid).startsWith('temp_')) {
                      const updated = {
                        ...sessions.value
                      };
                      delete updated[oldSid];
                      sessions.value = updated;
                    }
                    // 创建真正的会话标签
                    sessions.value[newSid] = {
                      id: newSid,
                      name: '新会话',
                      messages: [...currentMessages.value]
                    };
                    currentSessionId.value = newSid;
                    tempSession.value = false;
                  }
                } catch (e) {
                  currentMessages.value[aiMessageIndex].content += data;
                }
              } else {
                currentMessages.value[aiMessageIndex].content += data;
              }
              currentMessages.value = [...currentMessages.value];
              await new Promise(resolve => {
                requestAnimationFrame(() => {
                  scrollToBottom();
                  resolve();
                });
              });
            }
          }
        }
        loading.value = false;
        currentMessages.value[aiMessageIndex].meta = {
          status: 'done'
        };
        currentMessages.value = [...currentMessages.value];
        if (!tempSession.value && currentSessionId.value && sessions.value[currentSessionId.value]) {
          const sessMsgs = sessions.value[currentSessionId.value].messages;
          if (Array.isArray(sessMsgs) && sessMsgs.length) {
            const lastIndex = sessMsgs.length - 1;
            if (sessMsgs[lastIndex] && sessMsgs[lastIndex].role === 'assistant') {
              sessMsgs[lastIndex].content = currentMessages.value[aiMessageIndex].content;
            }
          }
        }
      } catch (err) {
        console.error('Stream error:', err);
        loading.value = false;
        currentMessages.value[aiMessageIndex].meta = {
          status: 'error'
        };
        currentMessages.value = [...currentMessages.value];
        ElMessage.error('流式传输出错');
      }
    }
    async function handleNormal(question) {
      if (tempSession.value) {
        const response = await api.post('/ai/chat/send-new-session', {
          question: question,
          modelType: selectedModel.value
        });
        if (response.data && response.data.status_code === 1000) {
          const sessionId = String(response.data.sessionID);
          const aiMessage = {
            role: 'assistant',
            content: response.data.information || ''
          };
          // 删除临时会话标签
          const oldSid = currentSessionId.value;
          if (oldSid && String(oldSid).startsWith('temp_')) {
            const updated = {
              ...sessions.value
            };
            delete updated[oldSid];
            sessions.value = updated;
          }
          // 创建真正的会话标签
          sessions.value[sessionId] = {
            id: sessionId,
            name: '新会话',
            messages: [{
              role: 'user',
              content: question
            }, aiMessage]
          };
          currentSessionId.value = sessionId;
          tempSession.value = false;
          currentMessages.value = [...sessions.value[sessionId].messages];
        } else {
          ElMessage.error(response.data?.status_msg || '发送失败');
          // 移除临时会话标签
          const oldSid = currentSessionId.value;
          if (oldSid && String(oldSid).startsWith('temp_')) {
            const updated = {
              ...sessions.value
            };
            delete updated[oldSid];
            sessions.value = updated;
            currentSessionId.value = null;
            tempSession.value = true;
          }
          currentMessages.value.pop();
        }
      } else {
        const sessionMsgs = sessions.value[currentSessionId.value].messages;
        sessionMsgs.push({
          role: 'user',
          content: question
        });
        const response = await api.post('/ai/chat/send', {
          question: question,
          modelType: selectedModel.value,
          sessionId: currentSessionId.value
        });
        if (response.data && response.data.status_code === 1000) {
          const aiMessage = {
            role: 'assistant',
            content: response.data.information || ''
          };
          sessionMsgs.push(aiMessage);
          currentMessages.value = [...sessionMsgs];
        } else {
          ElMessage.error(response.data?.status_msg || '发送失败');
          sessionMsgs.pop();
          currentMessages.value.pop();
        }
      }
    }
    const scrollToBottom = () => {
      if (messagesRef.value) {
        try {
          messagesRef.value.scrollTop = messagesRef.value.scrollHeight;
        } catch (e) {/* ignore */}
      }
    };
    const triggerFileUpload = () => {
      if (fileInput.value) fileInput.value.click();
    };
    const handleFileUpload = async event => {
      const file = event.target.files[0];
      if (!file) return;
      const fileName = file.name.toLowerCase();
      if (!fileName.endsWith('.md') && !fileName.endsWith('.txt')) {
        ElMessage.error('只允许上传 .md 或 .txt 文件');
        if (fileInput.value) fileInput.value.value = '';
        return;
      }
      try {
        uploading.value = true;
        const formData = new FormData();
        formData.append('file', file);
        const response = await api.post('/file/upload', formData, {
          headers: {
            'Content-Type': 'multipart/form-data'
          }
        });
        if (response.data && response.data.status_code === 1000) {
          ElMessage.success('文件上传成功');
        } else {
          ElMessage.error(response.data?.status_msg || '上传失败');
        }
      } catch (error) {
        console.error('File upload error:', error);
        ElMessage.error('文件上传失败');
      } finally {
        uploading.value = false;
        if (fileInput.value) fileInput.value.value = '';
      }
    };
    onMounted(() => {
      loadSessions();
    });

    // 会话列表计算属性，确保响应式更新
    const sessionList = computed(() => {
      return Object.values(sessions.value);
    });
    return {
      sessions: sessionList,
      currentSessionId,
      tempSession,
      currentMessages,
      inputMessage,
      loading,
      messagesRef,
      messageInput,
      selectedModel,
      isStreaming,
      uploading,
      fileInput,
      isComposing,
      sidebarCollapsed,
      sidebarWidth,
      toggleSidebar,
      startResize,
      renderMarkdown,
      playTTS,
      createNewSession,
      switchSession,
      deleteSession,
      syncHistory,
      sendMessage,
      triggerFileUpload,
      handleFileUpload
    };
  }
};
